using UnityEngine;

public class PlayerStats : MonoBehaviour
{
    public int health = 100;
    public int currency = 500;

    private void Update()
    {
        if (Input.GetKeyDown(KeyCode.D))
        {
            TakeDamage(10);
        }
    }

    public void TakeDamage(int damage)
    {
        health -= damage;
        if (health < 0)
        {
            health = 0;
        }
    }

    public bool CanBuyItem(int itemPrice)
    {
        return currency >= itemPrice;
    }

    public void BuyItem(int itemPrice)
    {
        if (CanBuyItem(itemPrice))
        {
            currency -= itemPrice;
            Debug.Log("Item purchased!");
        }
        else
        {
            Debug.LogWarning("Not enough currency to buy item.");
        }
    }
}